import Foundation

public actor ClaudeCodeConnector: UsageConnector {
    nonisolated public let vendor: Vendor = .claude

    private let claudeConfigPath: String
    private let logger: FileLogger
    private let session: URLSession
    private let keychainServiceName: String
    private let tokenProvider: (@Sendable () async throws -> String)?
    private let accountProvider: (@Sendable () -> AccountEmail?)?

    private var lastKnownMetrics: [UsageMetric] = []

    // Long enough for a cached keychain lookup; short enough to avoid stalling the poller
    private static let keychainTimeoutSeconds: Int = 10
    // Claude Pro/Max rate-limit policy — durations are fixed by Anthropic and not returned by the API
    private static let sessionWindowMinutes = DurationMinutes(rawValue: 300)
    private static let weeklyWindowMinutes  = DurationMinutes(rawValue: 10080)

    // Actor-isolated: safe without nonisolated(unsafe) since all access is on the actor
    private let isoFormatter = ISO8601DateFormatter()
    private let isoFormatterFractional: ISO8601DateFormatter = {
        let f = ISO8601DateFormatter()
        f.formatOptions = [.withInternetDateTime, .withFractionalSeconds]
        return f
    }()


    public init(
        claudeConfigPath: String? = nil,
        logger: FileLogger = Loggers.claude,
        session: URLSession = .shared,
        keychainServiceName: String = "Claude Code-credentials",
        tokenProvider: (@Sendable () async throws -> String)? = nil,
        accountProvider: (@Sendable () -> AccountEmail?)? = nil
    ) {
        let home = FileManager.default.homeDirectoryForCurrentUser.path
        self.claudeConfigPath = claudeConfigPath ?? "\(home)/.claude.json"
        self.logger = logger
        self.session = session
        self.keychainServiceName = keychainServiceName
        self.tokenProvider = tokenProvider
        self.accountProvider = accountProvider
    }

    // MARK: - UsageConnector

    nonisolated public func resolveActiveAccount() -> AccountEmail? {
        if let provider = accountProvider {
            return provider()
        }
        guard let data = FileManager.default.contents(atPath: claudeConfigPath) else {
            logger.log(.warning, "Cannot read \(claudeConfigPath)")
            return nil
        }
        do {
            let json = try JSONSerialization.jsonObject(with: data) as? [String: Any]
            let oauth = json?["oauthAccount"] as? [String: Any]
            return (oauth?["emailAddress"] as? String).map(AccountEmail.init(rawValue:))
        } catch {
            logger.log(.error, "Failed to parse \(claudeConfigPath): \(error)")
            return nil
        }
    }

    public func fetchUsages() async throws -> [VendorUsageEntry] {
        guard let earlyAccount = resolveActiveAccount() else {
            logger.log(.warning, "Cannot resolve active account — skipping fetch")
            return [errorEntry(account: "unknown", type: "account_unknown")]
        }
        logger.log(.info, "Fetching usages for account=\(earlyAccount)")

        let token: String
        do {
            if let provider = tokenProvider {
                token = try await provider()
            } else {
                token = try await fetchOAuthToken()
            }
        } catch {
            logger.log(.error, "Token retrieval failed: \(error)")
            return [errorEntry(account: earlyAccount, type: "token_error")]
        }

        // Re-read at HTTP dispatch time: if the user switched accounts while the token was being
        // fetched, the response must be attributed to whoever was active when the request went out.
        let account = resolveActiveAccount() ?? earlyAccount

        guard let url = URL(string: "https://api.anthropic.com/api/oauth/usage") else {
            return [errorEntry(account: account, type: "api_error")]
        }
        var request = URLRequest(url: url)
        request.setValue("Bearer \(token)", forHTTPHeaderField: "Authorization")
        // Required by the OAuth usage endpoint — beta flag must match the rollout date
        request.setValue("oauth-2025-04-20", forHTTPHeaderField: "anthropic-beta")
        request.timeoutInterval = 5

        let data: Data
        let response: URLResponse
        do {
            (data, response) = try await session.data(for: request)
        } catch {
            logger.log(.error, "API request failed: \(error)")
            return [errorEntry(account: account, type: "api_error")]
        }

        let httpCode = (response as? HTTPURLResponse)?.statusCode ?? -1
        logger.log(.info, "API response: HTTP \(httpCode)")

        if httpCode == 429 {
            let body = String(data: data, encoding: .utf8) ?? "<non-UTF8 body, \(data.count) bytes>"
            logger.log(.warning, "API rate-limited (HTTP 429): \(body)")
            return [errorEntry(account: account, type: "http_429", isActive: true, preservedMetrics: lastKnownMetrics)]
        }

        guard let http = response as? HTTPURLResponse, http.statusCode == 200 else {
            logger.log(.error, "API returned HTTP \(httpCode)")
            return [errorEntry(account: account, type: "http_\(httpCode)")]
        }

        logger.log(.debug, "API payload: \(Self.maskedPayload(data))")

        do {
            let usage = try parseAPIResponse(data)
            logger.log(.info, "Fetched successfully: session=\(usage.sessionPercent.map { "\($0)%" } ?? "nil") weekly=\(usage.weeklyPercent.map { "\($0)%" } ?? "nil") sonnet=\(usage.sonnetWeekly.map { "\($0.percent)%" } ?? "nil") opus=\(usage.opusWeekly.map { "\($0.percent)%" } ?? "nil")")
            // A window is emitted whenever utilization is known, even if resets_at is null
            // (fresh account, between cycles). A null reset date surfaces in the UI as "???"
            // rather than silently omitting the metric.
            var metrics: [UsageMetric] = []
            if let percent = usage.sessionPercent {
                metrics.append(.timeWindow(
                    name: "5h sessions (all models)",
                    resetAt: usage.sessionResetAt,
                    windowDuration: Self.sessionWindowMinutes,
                    usagePercent: UsagePercent(rawValue: percent)
                ))
            }
            if let percent = usage.weeklyPercent {
                metrics.append(.timeWindow(
                    name: "Weekly (all models)",
                    resetAt: usage.weeklyResetAt,
                    windowDuration: Self.weeklyWindowMinutes,
                    usagePercent: UsagePercent(rawValue: percent)
                ))
            }
            // Per-model weekly metrics are purely additive — absent keys are silently skipped
            let perModelDefs: [(metric: ModelWeeklyMetric?, name: String)] = [
                (usage.sonnetWeekly, "Weekly Sonnet"),
                (usage.opusWeekly, "Weekly Opus"),
            ]
            for def in perModelDefs {
                if let m = def.metric {
                    metrics.append(.timeWindow(
                        name: def.name,
                        resetAt: m.resetAt,
                        windowDuration: Self.weeklyWindowMinutes,
                        usagePercent: UsagePercent(rawValue: m.percent)
                    ))
                }
            }
            lastKnownMetrics = metrics
            return [VendorUsageEntry(
                vendor: vendor,
                account: account,
                isActive: true,
                lastAcquiredOn: ISODate(date: Date()),
                lastError: nil,
                metrics: metrics
            )]
        } catch {
            logger.log(.error, "Response parse failed: \(error)")
            logger.log(.warning, "Failed payload dump: \(Self.maskedPayload(data))")
            return [errorEntry(account: account, type: "parse_error")]
        }
    }

    // MARK: - Token

    private func fetchOAuthToken() async throws -> String {
        let serviceName = keychainServiceName
        return try await withCheckedThrowingContinuation { continuation in
            DispatchQueue.global().async {
                let process = Process()
                let pipe = Pipe()
                process.executableURL = URL(fileURLWithPath: "/usr/bin/security")
                process.arguments = ["find-generic-password", "-s", serviceName, "-w"]
                process.standardOutput = pipe
                process.standardError = FileHandle.nullDevice

                do {
                    try process.run()
                } catch {
                    continuation.resume(throwing: error)
                    return
                }

                // Keychain may prompt the user or hang if the login keychain is locked
                let timedOut = DispatchSemaphore(value: 0)
                DispatchQueue.global().asyncAfter(deadline: .now() + .seconds(Self.keychainTimeoutSeconds)) {
                    guard process.isRunning else { return }
                    process.terminate()
                    timedOut.signal()
                }

                let raw = pipe.fileHandleForReading.readDataToEndOfFile()
                process.waitUntilExit()

                // Check the flag rather than terminationReason, which may not
                // reflect SIGTERM reliably if the process handles the signal
                if timedOut.wait(timeout: .now()) == .success {
                    continuation.resume(throwing: ConnectorError.keychainTimeout(serviceName: serviceName, timeoutSeconds: Self.keychainTimeoutSeconds))
                    return
                }
                guard process.terminationStatus == 0 else {
                    continuation.resume(throwing: ConnectorError.keychainAccessDenied(serviceName: serviceName, exitCode: process.terminationStatus))
                    return
                }
                guard let jsonString = String(data: raw, encoding: .utf8)?.trimmingCharacters(in: .whitespacesAndNewlines),
                      !jsonString.isEmpty else {
                    continuation.resume(throwing: ConnectorError.keychainEmpty(serviceName: serviceName))
                    return
                }

                guard let jsonData = jsonString.data(using: .utf8) else {
                    continuation.resume(throwing: ConnectorError.tokenParseError(rawValue: jsonString))
                    return
                }
                let parsedJSON: [String: Any]
                do {
                    parsedJSON = try JSONSerialization.jsonObject(with: jsonData) as? [String: Any] ?? [:]
                } catch {
                    continuation.resume(throwing: ConnectorError.tokenParseError(rawValue: jsonString))
                    return
                }
                guard let oauthDict = parsedJSON["claudeAiOauth"] as? [String: Any],
                      let token = oauthDict["accessToken"] as? String,
                      !token.isEmpty else {
                    continuation.resume(throwing: ConnectorError.tokenParseError(rawValue: jsonString))
                    return
                }

                continuation.resume(returning: token)
            }
        }
    }

    // MARK: - Response parsing

    private static let sensitiveKeyPatterns = ["token", "key", "secret", "password", "email", "credential"]

    private static func maskedPayload(_ data: Data) -> String {
        guard let json = try? JSONSerialization.jsonObject(with: data) as? [String: Any] else {
            return "<non-JSON, \(data.count) bytes>"
        }
        let masked = maskSensitiveFields(json)
        guard let out = try? JSONSerialization.data(withJSONObject: masked, options: [.sortedKeys]),
              let str = String(data: out, encoding: .utf8) else {
            return "<serialization failed>"
        }
        return str
    }

    private static func maskSensitiveFields(_ dict: [String: Any]) -> [String: Any] {
        var result: [String: Any] = [:]
        for (key, value) in dict {
            let lower = key.lowercased()
            if sensitiveKeyPatterns.contains(where: { lower.contains($0) }) {
                result[key] = "***"
            } else if let nested = value as? [String: Any] {
                result[key] = maskSensitiveFields(nested)
            } else if let array = value as? [[String: Any]] {
                result[key] = array.map { maskSensitiveFields($0) }
            } else {
                result[key] = value
            }
        }
        return result
    }

    private struct ModelWeeklyMetric {
        let percent: Int
        let resetAt: ISODate?
    }

    private struct ParsedUsage {
        // Every window is optional: a freshly provisioned account (or an account
        // between reset cycles) returns `utilization: 0, resets_at: null` and must
        // not be treated as a parse failure.
        let sessionPercent: Int?
        let sessionResetAt: ISODate?
        let weeklyPercent: Int?
        let weeklyResetAt: ISODate?
        let sonnetWeekly: ModelWeeklyMetric?
        let opusWeekly: ModelWeeklyMetric?
    }

    private func parseAPIResponse(_ data: Data) throws -> ParsedUsage {
        let jsonObject = try JSONSerialization.jsonObject(with: data)
        guard let json = jsonObject as? [String: Any] else {
            throw ConnectorError.unexpectedAPIFormat(receivedKeys: [])
        }
        // Unknown top-level keys are ignored by design — the API evolves with experimental
        // fields (e.g. `omelette_promotional`, `iguana_necktie`) and we only consume the
        // windows we know about. Only a truly malformed payload (no known window at all)
        // escalates to an error.
        let session = extractOptionalModelMetric(from: json, key: "five_hour")
        let weekly = extractOptionalModelMetric(from: json, key: "seven_day")
        let sonnet = extractOptionalModelMetric(from: json, key: "seven_day_sonnet")
        let opus = extractOptionalModelMetric(from: json, key: "seven_day_opus")

        let hasFiveHourBlock = json["five_hour"] is [String: Any]
        let hasSevenDayBlock = json["seven_day"] is [String: Any]
        if !hasFiveHourBlock, !hasSevenDayBlock {
            logger.log(.warning, "No known usage window in payload — top-level keys: \(Array(json.keys))")
            throw ConnectorError.unexpectedAPIFormat(receivedKeys: Array(json.keys))
        }

        return ParsedUsage(
            sessionPercent: session.map { Int($0.percent) },
            sessionResetAt: session.flatMap { $0.resetAt.map { normalizeISO8601($0) } },
            weeklyPercent: weekly.map { Int($0.percent) },
            weeklyResetAt: weekly.flatMap { $0.resetAt.map { normalizeISO8601($0) } },
            sonnetWeekly: sonnet.map { ModelWeeklyMetric(percent: $0.percent, resetAt: $0.resetAt.map { normalizeISO8601($0) }) },
            opusWeekly: opus.map { ModelWeeklyMetric(percent: $0.percent, resetAt: $0.resetAt.map { normalizeISO8601($0) }) }
        )
    }

    /// Every usage window block is optional — a missing key or an unexpected shape is silently
    /// skipped. A null `resets_at` (fresh account, between cycles) is kept with `resetAt: nil`
    /// so the metric still surfaces in the UI as "???".
    private func extractOptionalModelMetric(from json: [String: Any], key: String) -> (percent: Int, resetAt: String?)? {
        guard let block = json[key] as? [String: Any] else {
            return nil
        }
        guard let util = block["utilization"] as? Double else {
            logger.log(.debug, "Block '\(key)' present but utilization missing — skipped")
            return nil
        }
        let resetAt = block["resets_at"] as? String
        if resetAt == nil {
            logger.log(.debug, "Block '\(key)' has null resets_at — metric emitted without reset date")
        }
        return (percent: Int(util.rounded()), resetAt: resetAt)
    }

    /// Strips sub-second precision from API-provided ISO8601 strings so downstream
    /// consumers can rely on the standard formatter (no fractional-seconds option needed).
    /// Returns the original string unchanged if it cannot be parsed.
    private func normalizeISO8601(_ raw: String) -> ISODate {
        if let date = isoFormatterFractional.date(from: raw) ?? isoFormatter.date(from: raw) {
            return ISODate(rawValue: isoFormatter.string(from: date))
        }
        return ISODate(rawValue: raw)
    }

    // MARK: - Helpers

    private func errorEntry(account: AccountEmail, type: String, isActive: Bool = false, preservedMetrics: [UsageMetric] = []) -> VendorUsageEntry {
        return VendorUsageEntry(
            vendor: vendor,
            account: account,
            isActive: isActive,
            lastAcquiredOn: nil,
            lastError: UsageError(timestamp: ISODate(date: Date()), type: type),
            metrics: preservedMetrics
        )
    }
}

public enum ConnectorError: Error, CustomStringConvertible {
    case keychainAccessDenied(serviceName: String, exitCode: Int32)
    case keychainEmpty(serviceName: String)
    case keychainTimeout(serviceName: String, timeoutSeconds: Int)
    case tokenParseError(rawValue: String)
    case unexpectedAPIFormat(receivedKeys: [String])

    public var description: String {
        switch self {
        case let .keychainAccessDenied(svc, code):
            "Keychain access denied for service '\(svc)' (exit \(code))"
        case let .keychainEmpty(svc):
            "Keychain item is empty for service '\(svc)'"
        case let .keychainTimeout(svc, secs):
            "Keychain access timed out after \(secs)s for service '\(svc)'"
        case let .tokenParseError(raw):
            "Failed to parse OAuth token — raw value preview: '\(raw.prefix(80))'"
        case let .unexpectedAPIFormat(keys):
            "API response does not match expected format — top-level keys: \(keys)"
        }
    }
}

import Foundation

// MARK: - Root

/// The top-level file model: `{ usages: [...], outages?: [...] }`.
///
/// `outages` is an optional sibling written by an upstream status-fetching process.
/// When no incident is ongoing the upstream writer is expected to drop the key
/// entirely; the encoder here honours that convention by emitting nothing when
/// the in-memory array is empty.
public struct UsagesFile: Codable, Equatable, Sendable {
    public var usages: [VendorUsageEntry]
    public var outages: [Outage]

    public init(usages: [VendorUsageEntry] = [], outages: [Outage] = []) {
        self.usages = usages
        self.outages = outages
    }

    /// Grouped view for the UI — vendors without outages are omitted.
    public var outagesByVendor: [Vendor: [Outage]] {
        Dictionary(grouping: outages, by: \.vendor)
    }

    private enum CodingKeys: String, CodingKey {
        case usages, outages
    }

    public init(from decoder: Decoder) throws {
        let container = try decoder.container(keyedBy: CodingKeys.self)
        usages = try container.decodeIfPresent([VendorUsageEntry].self, forKey: .usages) ?? []
        outages = try container.decodeIfPresent([Outage].self, forKey: .outages) ?? []
    }

    public func encode(to encoder: Encoder) throws {
        var container = encoder.container(keyedBy: CodingKeys.self)
        try container.encode(usages, forKey: .usages)
        // Upstream convention: absent key when no ongoing outage — mirror that on write
        // so the file never carries a stale empty array between incidents.
        if !outages.isEmpty {
            try container.encode(outages, forKey: .outages)
        }
    }
}

// MARK: - VendorUsageEntry

public struct VendorUsageEntry: Codable, Equatable, Sendable, Identifiable {
    public var id: String { "\(vendor.rawValue):\(account.rawValue)" }

    public let vendor: Vendor
    public let account: AccountEmail
    public var isActive: Bool
    public var lastAcquiredOn: ISODate?
    public var lastError: UsageError?
    public var metrics: [UsageMetric]

    public init(
        vendor: Vendor,
        account: AccountEmail,
        isActive: Bool = false,
        lastAcquiredOn: ISODate? = nil,
        lastError: UsageError? = nil,
        metrics: [UsageMetric] = []
    ) {
        self.vendor = vendor
        self.account = account
        self.isActive = isActive
        self.lastAcquiredOn = lastAcquiredOn
        self.lastError = lastError
        self.metrics = metrics
    }
}

// MARK: - Error

public struct UsageError: Codable, Equatable, Sendable {
    public let timestamp: ISODate
    public let type: String

    public init(timestamp: ISODate, type: String) {
        self.timestamp = timestamp
        self.type = type
    }
}

// MARK: - Outage

/// An active incident on a vendor's platform, written by an upstream status-fetching process.
/// The upstream writer removes entries as incidents resolve, so a missing or empty
/// `outages` array means "all clear".
public struct Outage: Codable, Equatable, Sendable, Identifiable {
    public let vendor: Vendor
    public let errorMessage: String
    public let severity: OutageSeverity
    public let since: ISODate
    public let href: URL?

    /// Composite id — outages have no stable upstream id in this shape, so we
    /// derive one from the fields that together identify a single incident row.
    public var id: String {
        "\(vendor.rawValue)|\(since.rawValue)|\(href?.absoluteString ?? "")"
    }

    public init(
        vendor: Vendor,
        errorMessage: String,
        severity: OutageSeverity,
        since: ISODate,
        href: URL? = nil
    ) {
        self.vendor = vendor
        self.errorMessage = errorMessage
        self.severity = severity
        self.since = since
        self.href = href
    }

    private enum CodingKeys: String, CodingKey {
        case vendor, errorMessage, severity, since, href
    }

    public init(from decoder: Decoder) throws {
        let container = try decoder.container(keyedBy: CodingKeys.self)
        vendor = try container.decode(Vendor.self, forKey: .vendor)
        errorMessage = try container.decode(String.self, forKey: .errorMessage)
        severity = try container.decode(OutageSeverity.self, forKey: .severity)
        since = try container.decode(ISODate.self, forKey: .since)
        if let hrefString = try container.decodeIfPresent(String.self, forKey: .href) {
            guard let parsed = URL(string: hrefString) else {
                throw DecodingError.dataCorruptedError(
                    forKey: .href, in: container,
                    debugDescription: "Invalid URL string: \(hrefString)")
            }
            href = parsed
        } else {
            href = nil
        }
    }
}

// MARK: - Metric (polymorphic on "type" discriminator)

public enum UsageMetric: Codable, Equatable, Sendable {
    case timeWindow(name: String, resetAt: ISODate?, windowDuration: DurationMinutes, usagePercent: UsagePercent)
    case payAsYouGo(name: String, currentAmount: Double, currency: String)
    /// A metric type not yet known to this client; retained for round-trip fidelity.
    case unknown(String)

    // MARK: Kind

    public var kind: MetricKind {
        switch self {
        case .timeWindow:       .timeWindow
        case .payAsYouGo:       .payAsYouGo
        case .unknown(let t):   .unknown(t)
        }
    }

    // MARK: Coding

    private enum CodingKeys: String, CodingKey {
        case type, name, resetAt
        case windowDuration = "windowDurationMinutes"
        case usagePercent, currentAmount, currency
    }

    public init(from decoder: Decoder) throws {
        let container = try decoder.container(keyedBy: CodingKeys.self)
        let metricKind = try container.decode(MetricKind.self, forKey: .type)
        switch metricKind {
        case .timeWindow:
            self = .timeWindow(
                name: try container.decode(String.self, forKey: .name),
                resetAt: try container.decodeIfPresent(ISODate.self, forKey: .resetAt),
                windowDuration: try container.decode(DurationMinutes.self, forKey: .windowDuration),
                usagePercent: try container.decode(UsagePercent.self, forKey: .usagePercent)
            )
        case .payAsYouGo:
            self = .payAsYouGo(
                name: try container.decode(String.self, forKey: .name),
                currentAmount: try container.decode(Double.self, forKey: .currentAmount),
                currency: try container.decode(String.self, forKey: .currency)
            )
        case .unknown(let t):
            self = .unknown(t)
        }
    }

    public func encode(to encoder: Encoder) throws {
        var container = encoder.container(keyedBy: CodingKeys.self)
        switch self {
        case let .timeWindow(name, resetAt, windowDuration, usagePercent):
            try container.encode(MetricKind.timeWindow, forKey: .type)
            try container.encode(name, forKey: .name)
            try container.encodeIfPresent(resetAt, forKey: .resetAt)
            try container.encode(windowDuration, forKey: .windowDuration)
            try container.encode(usagePercent, forKey: .usagePercent)
        case let .payAsYouGo(name, currentAmount, currency):
            try container.encode(MetricKind.payAsYouGo, forKey: .type)
            try container.encode(name, forKey: .name)
            try container.encode(currentAmount, forKey: .currentAmount)
            try container.encode(currency, forKey: .currency)
        case let .unknown(t):
            // Only the type discriminator round-trips; unknown fields are not preserved
            try container.encode(MetricKind.unknown(t), forKey: .type)
        }
    }
}

